tasks.solution:
// IAM role is superior because:
// 1. No static credentials to rotate, leak, or accidentally commit to source control.
// 2. Credentials are automatically rotated by AWS (STS short-lived tokens).
// 3. The role can be audited and scoped precisely (e.g., only ecr:GetAuthorizationToken
//    and ecr:BatchCheckLayerAvailability/PutImage for the specific repository).
// 4. If the Jenkins host is compromised, the window of credential exposure is minimal
//    because tokens expire in minutes/hours rather than persisting indefinitely.

// Fallback: inject stored credentials with withCredentials
stage('Push to ECR') {
    steps {
        withCredentials([[
            $class: 'AmazonWebServicesCredentialsBinding',
            credentialsId: 'aws-ecr-creds',
            accessKeyVariable: 'AWS_ACCESS_KEY_ID',
            secretKeyVariable: 'AWS_SECRET_ACCESS_KEY'
        ]]) {
            sh """
              aws ecr get-login-password --region ${AWS_REGION} \\
                | docker login --username AWS --password-stdin ${REGISTRY}
              docker push ${REGISTRY}/${ECR_REPO}:${IMAGE_TAG}
            """
        }
    }
}
